import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const probe = await callMcpSkillsParallel({
    label: "world-cup-winner-liquidity-probe",
    calls: [
      {
        key: "event-outcomes",
        toolId,
        toolName: "search_and_get_outcomes",
        args: {
          query: "current World Cup winner market",
          category: "sports"
        }
      },
      {
        key: "trending-context",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          category: "sports",
          limit: 20,
          sortBy: "volume"
        }
      }
    ]
  });

  const outcomesResult = probe.results.find((entry) => entry.key === "event-outcomes");
  const trendingResult = probe.results.find((entry) => entry.key === "trending-context");

  if (!outcomesResult || outcomesResult.status !== "fulfilled") {
    return {
      stopReason: "missing_event_outcomes_probe",
      attemptedBranches: ["search_and_get_outcomes", "discover_trending_markets"],
      missingData: ["event outcomes for current World Cup winner market"],
      probeTelemetry: probe.summary
    };
  }

  const eventData = outcomesResult.value || {};
  const outcomes = Array.isArray(eventData.outcomes) ? eventData.outcomes : [];

  const rankedByIntent = pickTopSemanticCandidates({
    target: "representative YES-side favorite in the current World Cup winner market",
    candidates: outcomes,
    requiredTerms: ["World Cup", "winner"],
    avoidTerms: ["resolved", "placeholder", "inactive"],
    limit: 3
  });

  const selectedOutcome =
    rankedByIntent[0] ||
    outcomes
      .slice()
      .sort((a, b) => {
        const ap = typeof a?.price === "number" ? a.price : -1;
        const bp = typeof b?.price === "number" ? b.price : -1;
        if (bp !== ap) return bp - ap;
        const av = typeof a?.volume === "number" ? a.volume : -1;
        const bv = typeof b?.volume === "number" ? b.volume : -1;
        return bv - av;
      })[0] ||
    null;

  if (!selectedOutcome || !selectedOutcome.tokenId) {
    return {
      stopReason: "no_representative_outcome_found",
      attemptedBranches: ["deterministic_semantic_targeting", "price_volume_fallback"],
      missingData: ["tokenId for selected World Cup winner outcome"],
      eventTitle: eventData.eventTitle || null,
      outcomesCount: outcomes.length,
      trendingContext:
        trendingResult && trendingResult.status === "fulfilled" ? trendingResult.value : null,
      probeTelemetry: probe.summary
    };
  }

  const liquidity = await callMcpSkill({
    toolId,
    toolName: "analyze_market_liquidity",
    args: {
      tokenId: selectedOutcome.tokenId
    }
  });

  return {
    eventTitle: eventData.eventTitle || null,
    eventSlug: eventData.eventSlug || null,
    searchMethod: eventData.searchMethod || null,
    selectedOutcome: {
      name: selectedOutcome.name || null,
      tokenId: selectedOutcome.tokenId,
      conditionId: selectedOutcome.conditionId || null,
      currentPrice: selectedOutcome.price ?? selectedOutcome.currentPrice ?? null,
      volume: selectedOutcome.volume ?? null
    },
    liquidityAnalysis: {
      market: liquidity.market,
      tokenId: liquidity.tokenId,
      currentPrice: liquidity.currentPrice,
      spread: liquidity.spread,
      liquidityScore: liquidity.liquidityScore,
      whaleCost: liquidity.whaleCost,
      depth: liquidity.depth || null,
      depthWithin2Percent: liquidity.depthWithin2Percent || null,
      recommendation: liquidity.recommendation || null,
      fetchedAt: liquidity.fetchedAt || null
    },
    requestedExits: {
      "1000": liquidity.whaleCost?.sell1k ?? null,
      "5000": liquidity.whaleCost?.sell5k ?? null,
      "10000": liquidity.whaleCost?.sell10k ?? null
    },
    probeTelemetry: probe.summary
  };
}

